{
  "type": "object",
  "properties": {
    "location": {
      "type": "string",
      "description": "City name like 'San Francisco' or 'New York'"
    },
    "units": {
      "type": "string",
      "enum": ["celsius", "fahrenheit"],
      "description": "Temperature unit (default: celsius)"
    }
  },
  "required": ["location"]
}

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";

const server = new McpServer({
  name: "weather-server",
  version: "1.0.0"
});

server.tool(
  "get_weather",
  "Get current weather for a location",
  {
    location: { type: "string" },
    units: { type: "string", enum: ["celsius", "fahrenheit"] }
  },
  async ({ location, units }) => {
    const temperature = await fetchWeatherApi(location);
    return {
      content: [{ type: "text", text: `Sunny, ${temperature}°${units[0]}` }]
    };
  }
);

using ModelContextProtocol.Server;

[McpServerToolType]
public class WeatherTools {
    [McpServerTool, Description("Get current weather for a location")]
    public static string GetWeather(string location, string units = "celsius") {
        var temperature = FetchWeatherApi(location);
        return $"Sunny, {temperature}°{units[0]}";
    }
}
